import React, { useState } from 'react'

const Sidebar = () => {
  const [images,setimages] = useState([]);
  const [Upload,setUpload] = useState(false);

  const addimage = (event)=>{
    const image = event.target.files[0];
    if(image){
      setimages([...images,URL.createObjectURL(image)]);
    }
  }

  return (
    <div>
      <aside className='flex fixed left-3 top-20 w-fit gap-2 z-20 pointer-events-auto'>
        <ul className='flex flex-col justify-center text-2xl opacity-90 gap-3 bg-white/80 backdrop-blur-sm p-2 rounded-xl border border-gray-300 shadow-md [&>li]:cursor-pointer [&>li]:active:bg-sky-500 [&>li]:rounded-md [&>li]:p-2'>
            <li className='flex flex-col items-center' style={{background:Upload===true?"#3a98f7":""}} onClick={()=>setUpload(!Upload)}>
              <i className="fa-solid fa-cloud-arrow-up"></i>
              <span className='text-[10px] font-semibold'>uploads</span>
            </li>
        </ul>
        {Upload && (
          <div className="box border-2 rounded-xl border-black flex flex-col bg-sky-100/95 backdrop-blur-md items-center shadow-2xl p-2 z-30">
            <input className='img cursor-pointer p-2 text-xs' type="file" accept='.png,.jpg,.jpeg,.gif,.webp' onChange={addimage}/>
            <hr className='my-2 border-black/20 w-full' />
            <div className="flex flex-wrap justify-center gap-2 max-w-[280px] max-h-[300px] overflow-y-auto">
              {images.map((img, idx)=>(
                <img key={idx} src={img} className='cursor-pointer border-2 hover:border-black rounded-lg transition-transform hover:scale-105' style={{"width":"80px", "height":"80px", "objectFit":"cover"}} alt="Upload" />
              ))}
            </div>
          </div>
        )}
      </aside>
    </div>
  )
}

export default Sidebar
